#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t N;
        scanf("%llu", &N);
        uint64_t zeros = 0;
        for (uint64_t d = 5; d <= N; d *= 5) {
            zeros += N / d;
        }
        printf("%llu\n", zeros);
    }
    return 0;
}

