code.Python3:
#!/usr/bin/env python3
import sys

def trailing_zeros(n: int) -> int:
    zeros = 0
    while n:
        n //= 5
        zeros += n
    return zeros

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        n = int(data[i])
        out.append(str(trailing_zeros(n)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

